// Collect all rows into one item
const rows = $input.all().map(item => item.json);
return [{ json: { shippingData: rows } }];

// Build complete shipping label HTML directly — no AI needed
const rows = $input.first().json.shippingData || [];

function safe(val) {
  return String(val == null ? '' : val)
    .replace(/&/g,'&amp;')
    .replace(/</g,'&lt;')
    .replace(/>/g,'&gt;');
}

const LABELS_PER_PAGE = 8;
const pages = [];
for (let i = 0; i < rows.length; i += LABELS_PER_PAGE) {
  pages.push(rows.slice(i, i + LABELS_PER_PAGE));
}

function makeLabel(row, idx) {
  if (!row) return '<div class="label empty"></div>';
  return `
    <div class="label">
      <div class="label-to">TO:</div>
      <div class="label-name">${safe(row['Name'])}</div>
      <div class="label-line">&#128222; ${safe(row['Phone Number'])}</div>
      <div class="label-line">${safe(row['Address 1'])}</div>
      <div class="label-line">${safe(row['Address 2'])}</div>
      <div class="label-pin">PIN: ${safe(row['Pin Code'])}</div>
      <div class="barcode">${Array.from({length:28},(_,i)=>`<span style="height:${6+Math.abs(Math.sin(i*1.3)*8)|0}px"></span>`).join('')}</div>
    </div>`;
}

function makePage(pageRows, pageIdx) {
  const padded = [...pageRows];
  while (padded.length < LABELS_PER_PAGE) padded.push(null);
  return `<div class="page"><div class="grid">${padded.map((r,i)=>makeLabel(r, pageIdx*8+i)).join('')}</div></div>`;
}

const html = `<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
<style>
*{margin:0;padding:0;box-sizing:border-box;}
body{font-family:Arial,sans-serif;background:#fff;}
.page{
  width:210mm;min-height:297mm;
  padding:6mm;
  page-break-after:always;
}
.grid{
  display:grid;
  grid-template-columns:1fr 1fr;
  grid-template-rows:repeat(4,1fr);
  gap:4mm;
  width:100%;
  height:285mm;
}
.label{
  border:1.5px solid #000;
  border-radius:4px;
  padding:4mm;
  display:flex;
  flex-direction:column;
  gap:1.2mm;
  background:#fff;
  position:relative;
}
.label.empty{border:1.5px dashed #ccc;background:#fafafa;}
.label-to{font-size:8pt;font-weight:bold;color:#555;letter-spacing:1px;}
.label-name{font-size:13pt;font-weight:bold;color:#000;border-bottom:1px solid #ddd;padding-bottom:1.5mm;margin-bottom:1mm;}
.label-line{font-size:8.5pt;color:#333;line-height:1.5;}
.label-pin{font-size:11pt;font-weight:bold;color:#000;margin-top:auto;padding-top:1.5mm;border-top:1px solid #ddd;letter-spacing:2px;}
.barcode{display:flex;align-items:flex-end;gap:1.5px;height:14px;margin-top:2mm;}
.barcode span{width:2px;background:#000;display:inline-block;}
@media print{
  body{margin:0;}
  .page{page-break-after:always;}
  @page{size:A4;margin:0;}
}
</style>
</head>
<body>
${pages.map((p,i)=>makePage(p,i)).join('')}
</body>
</html>`;

return [{ json: { html, total: rows.length } }];
